	/**
	 * A text field to input which type of ball is generated of the model
	 */
	private final JTextField ballTextField = new JTextField();

	/**
	 * A button which triggers the process to make the ball specified in the text field
	 */
	private final JButton makeBallButton = new JButton("Make ball");

	/**
	 * A button which clears all the balls generated by the model from the view
	 */
	private final JButton clearButton = new JButton("Clear all");

	/**
	 * The center panel of the GUI, contains the balls generated by the model
